mapper.insert:
INSERT INTO fishing_log (
user_id, sea_id, fishing_date,
fishing_gear, create_time, update_time
) VALUES (
#{userId}, #{seaId}, #{fishingDate},
#{fishingGear}, #{createTime}, #{updateTime}
)

mapper.select:
SELECT
fl.log_id AS logId,
IFNULL(sa.sea_name, '未配置海域') AS seaName,
fl.fishing_date AS fishingDate,
fl.fishing_gear AS fishingGear,
fl.is_compliant AS isCompliant,  
fl.uncompliant_reason AS uncompliantReason,  
DATE_FORMAT(IFNULL(fl.create_time, NOW()), '%Y-%m-%d %H:%i:%s') AS createTime
FROM fishing_log fl
LEFT JOIN sea_area sa ON fl.sea_id = sa.sea_id
WHERE fl.user_id = #{userId}

    AND fl.fishing_date = #{fishingDate}


    AND fl.sea_id = #{seaId}


    AND fl.is_compliant = #{isCompliant}

LIMIT #{pageNum}, #{pageSize}

SELECT COUNT(*)
FROM fishing_log fl
WHERE fl.user_id = #{userId}

    AND fl.fishing_date = #{fishingDate}


    AND fl.sea_id = #{seaId}


    AND fl.is_compliant = #{isCompliant}

mapper.update:
UPDATE fishing_log

    is_compliant = #{isCompliant},
    uncompliant_reason = #{uncompliantReason},
    update_time = #{updateTime}

WHERE log_id = #{logId}
